	private static final String RESOURCE_ROOT = "/org/eclipse/rdf4j/query/algebra/equivalence/internal/";

	/**
	 * RDF4J's runtime REDUCED iteration can make a nested operand's evaluation schedule observable even when callers
	 * only inspect SET support. Removing REDUCED from this fuzz-discovered tree changes the support on the empty
	 * dataset, so the runtime checker must not apply the specification-level support-preservation rule.
	 */
	@Test
	void runtimeReducedIsNotHiddenBySetObservation() throws Exception {
		TupleExpr original = parseTupleExpr("reduced-runtime-set-soundness-original.json");
		TupleExpr candidate = parseTupleExpr("reduced-runtime-set-soundness-candidate.json");
		EvaluationCase empty = EvaluationCase.builder("empty dataset").build();

		EvaluationOutcome originalOutcome = evaluateAllowingError(original, empty);
		EvaluationOutcome candidateOutcome = evaluateAllowingError(candidate, empty);
		assertFalse(
				originalOutcome.sameAs(candidateOutcome, ObservationMode.SET),
				() -> "the preserved fuzz witness no longer distinguishes SET support: "
						+ originalOutcome + " versus " + candidateOutcome);

		CheckOptions options = CheckOptions.builder()
				.observationMode(ObservationMode.SET)
				.boundedCounterexampleSearch(false)
				.addEvaluationCase(empty)
				.build();
		assertDatasetIsVerifiedWitness(options, original, candidate);
		assertNotEquivalentWithVerifiedCounterexample(options, original, candidate);
	}

	/**
	 * The LeftJoin condition {@code ?x > 5} reads {@code ?x} bound by the sibling join operand. Because {@code ?x} is a
	 * may-bind name of the LeftJoin's left arg (second Union branch), RDF4J's well-designed-left-join check exposes the
	 * sibling's binding to the condition at runtime, so join order is observable and the analyzer must count the
	 * condition's unsatisfied reads as incoming reads.
	 */
	@Test
	void leftJoinConditionReadBlocksJoinCommutation() throws Exception {
		TupleExpr original = parseTupleExpr("leftjoin-condition-blind-spot.json");
		TupleExpr transformed = commuteTopLevelJoin(original);
		EvaluationCase dataset = parseDataset("leftjoin-condition-blind-spot.nt",
				"left join condition reads sibling join binding");

		EvaluationOutcome originalOutcome = evaluate(original, dataset);
		EvaluationOutcome transformedOutcome = evaluate(transformed, dataset);

		// Original order: the condition sees ?x=10 from the sibling operand, holds, and binds ?c.
		assertEquals(1, originalOutcome.getSequence().size(), originalOutcome::toString);
		Map<String, Value> originalBindings = originalOutcome.getSequence().get(0).getBindings();
		assertEquals(Set.of("s", "x", "a", "b", "c"), originalBindings.keySet(), originalOutcome::toString);
		assertEquals(VF.createIRI("urn:counterexample:c1"), originalBindings.get("c"), originalOutcome::toString);

		// Commuted order: the LeftJoin is evaluated first, ?x is unbound, the condition errors to false, ?c stays
		// unbound.
		assertEquals(1, transformedOutcome.getSequence().size(), transformedOutcome::toString);
		Map<String, Value> transformedBindings = transformedOutcome.getSequence().get(0).getBindings();
		assertEquals(Set.of("s", "x", "a", "b"), transformedBindings.keySet(), transformedOutcome::toString);

		assertFalse(originalOutcome.sameAs(transformedOutcome, ObservationMode.BAG),
				() -> "expected meaningfully different results: " + originalOutcome + " versus " + transformedOutcome);

		CheckOptions options = checkOptions(dataset);
		assertDatasetIsVerifiedWitness(options, original, transformed);
		assertNotEquivalentWithVerifiedCounterexample(options, original, transformed);
	}

